function submitApplication(application) {
  const appl = Object.assign({}, application);
  appl.phone = parsePhoneNumberFromString(application.phone, 'DE').number;
  appl.acceptMandate = application.acceptMandate[0] == 'on';
  appl.acceptPrices = application.acceptPrices[0] == 'on';
  appl.acceptPrivacy = application.acceptPrivacy[0] == 'on';
  appl.acceptNewsletter = application.acceptNewsletter[0] == 'on';
  appl.amount = parseInt(application.amount);
  appl.amountCents = parseInt(application.amountCents);
  appl.paymentCycle = parseInt(application.paymentCycle);

  const response = Applications.create(appl).then(
    function onResult(res) {
      alert(
        'Der Antrag mit der ID ' +
          res.body.HashId +
          ' wurde erfolgreich übermittelt :-)',
      );
      window.widget.setState({
        hashId: res.body.HashId,
        firstName: appl.firstName,
        email: appl.email,
        acceptNewsletter: appl.acceptNewsletter,
      });
    },
    function onError(err) {
      var error =
        'Bei der Verarbeitung der Daten ist ein Fehler passiert. Es existiert bereits ein Mitgliedsantrag zu den angegebenen Daten oder die Daten wurden vom Server abgelehnt.';
      alert(error);
      window.widget.setState({error: error});
    },
  );
}

