class ApplicationWidget extends Component {
  constructor(props) {
    super(props);
    this.state = {
      hashId: '',
      firstName: '',
      email: '',
      acceptNewsletter: false,
      error: false,
    };
  }

  componentDidMount() {
    window.widget = this;
  }

  render() {
    if (this.state.hashId == '') {
      return (
        <div>
          <Title
            title="Mitmachen - Die Föderalen"
            url={createUrl('/mitmachen')}
          />
          <TitleRow>
            <Col>
              <h1>Antrag auf Mitgliedschaft in der Partei DIE FÖDERALEN</h1>
            </Col>
          </TitleRow>
          <ContentRow>
            <Col>
              <Text>
                Hiermit beantrage ich, meinen Eintritt in die Partei DIE
                FÖDERALEN. Ich bekenne mich zu den programmatischen Grundsätzen
                der Partei DIE FÖDERALEN und erkenne die Bundessatzung der
                Partei DIE FÖDERALEN an. Die Beitragstabelle, Bundessatzung,
                Bundesfinanzordnung, Wahlordnung, Schiedgerichtsordnung und das
                Grundsatzprogramm befindet sich <a href="/satzung">hier</a>.
              </Text>
            </Col>
          </ContentRow>
          {this.state.error && (
            <ContentRow>
              <Col>
                <Alert variant="danger">{this.state.error}</Alert>
              </Col>
            </ContentRow>
          )}
          <ApplicationForm />
        </div>
      );
    } else {
      return (
        <div>
          <Title
            title="Dein Mitgliedsantrag wurde erfolgreich übermittelt - Die Föderalen"
            url={createUrl('/mitmachen')}
          />
          <TitleRow>
            <Col>
              <h1>Dein Mitgliedsantrag wurde erfolgreich übermittelt</h1>
            </Col>
          </TitleRow>
          <ContentRow>
            <Col>
              <Text>
                Vielen Dank, {this.state.firstName}! Dein Mitgliedsantrag wurde
                erfolgreich übermittelt. Dein Antrag wird unter folgender ID
                bearbeitet:
                <p>
                  <b>{this.state.hashId}</b>
                </p>
                <p>
                  An die angebene E-Mail-Adresse <b>{this.state.email}</b> wurde
                  zur Bestätigung eine E-Mail geschickt. Bitte verifiziere deine
                  E-Mail-Adresse, damit wir deinen Antrag schneller bearbeiten
                  können.
                </p>
                {this.state.acceptNewsletter && (
                  <p>
                    Um das kostenlose Newsletter zu bestätigen, erhälst du eine
                    separate E-Mail.
                  </p>
                )}
                <p>
                  Zur Sicherheit{' '}
                  <a href="javascript:if(window.print)window.print()">drucke</a>{' '}
                  nun diese Seite aus oder speichere dir die Antrags-ID. Bei
                  Probleme kannst du dich mit der Antrags-ID und deiner
                  E-Mail-Adresse an unseren Support wenden.
                </p>
              </Text>
            </Col>
          </ContentRow>
        </div>
      );
    }
  }
}

class Mitmachen extends Component<Props> {
  render() {
    return (
      <DefaultLayout navigation={navigation}>
        <ApplicationWidget />
      </DefaultLayout>
    );
  }
}

export default Mitmachen;
